constructor(options: HonoOptions<E> = {}) {
  // Implementation of app.get(...handlers[]) or app.get(path, ...handlers[])
  const allMethods = [...METHODS, METHOD_NAME_ALL_LOWERCASE]
  allMethods.forEach((method) => {
    this[method] = (args1: string | H, ...args: H[]) => {
      if (typeof args1 === 'string') {
        this.#path = args1
      } else {
        this.#addRoute(method, this.#path, args1)
      }
      args.forEach((handler) => {
        this.#addRoute(method, this.#path, handler)
      })
      return this as any
    }
  })

  // Implementation of app.on(method, path, ...handlers[])
  this.on = (method: string | string[], path: string | string[], ...handlers: H[]) => {
    for (const p of [path].flat()) {
      this.#path = p
      for (const m of [method].flat()) {
        handlers.map((handler) => {
          this.#addRoute(m.toUpperCase(), this.#path, handler)
        })
      }
    }
    return this as any
  }

  // Implementation of app.use(...handlers[]) or app.use(path, ...handlers[])
  this.use = (arg1: string | MiddlewareHandler<any>, ...handlers: MiddlewareHandler<any>[]) => {
    if (typeof arg1 === 'string') {
      this.#path = arg1
    } else {
      this.#path = '*'
      handlers.unshift(arg1)
    }
    handlers.forEach((handler) => {
      this.#addRoute(METHOD_NAME_ALL, this.#path, handler)
    })
    return this as any
  }

  const { strict, ...optionsWithoutStrict } = options
  Object.assign(this, optionsWithoutStrict)
  this.getPath = (strict ?? true) ? (options.getPath ?? getPath) : getPathNoStrict
}

export const ipRestriction = (
  getIP: GetIPAddr,
  { denyList = [], allowList = [] }: IPRestrictionRules,
  onError?: (
    remote: { addr: string; type: AddressType },
    c: Context
  ) => Response | Promise<Response>
): MiddlewareHandler => {
  const allowLength = allowList.length

  const denyMatcher = buildMatcher(denyList)
  const allowMatcher = buildMatcher(allowList)

  const blockError = (c: Context): HTTPException =>
    new HTTPException(403, {
      res: c.text('Forbidden', {
        status: 403,
      }),
    })

  return async function ipRestriction(c, next) {
    const connInfo = getIP(c)
    const addr = typeof connInfo === 'string' ? connInfo : connInfo.remote.address
    if (!addr) {
      throw blockError(c)
    }
    const type =
      (typeof connInfo !== 'string' && connInfo.remote.addressType) || distinctRemoteAddr(addr)

    const remoteData = { addr, type, isIPv4: type === 'IPv4' }

    try {
      if (denyMatcher(remoteData)) {
        if (onError) {
          return onError({ addr, type }, c)
        }
        throw blockError(c)
      }
      if (allowMatcher(remoteData)) {
        return await next()
      }
    } catch (e) {
      if (
        e instanceof TypeError &&
        (e as InvalidIPAddressError).code === INVALID_IP_ADDRESS_ERROR_CODE
      ) {
        // If an invalid IP address is specified, treat it as if no IP address was specified
        throw blockError(c)
      }
      throw e
    }

    if (allowLength === 0) {
      return await next()
    } else {
      if (onError) {
        return await onError({ addr, type }, c)
      }
      throw blockError(c)
    }
  }
}

export class Factory<E extends Env = Env, P extends string = string> {
  private initApp?: InitApp<E>
  #defaultAppOptions?: HonoOptions<E>

  constructor(init?: { initApp?: InitApp<E>; defaultAppOptions?: HonoOptions<E> }) {
    this.initApp = init?.initApp
    this.#defaultAppOptions = init?.defaultAppOptions
  }

  createApp = (options?: HonoOptions<E>): Hono<E> => {
    const app = new Hono<E>(
      options && this.#defaultAppOptions
        ? { ...this.#defaultAppOptions, ...options }
        : (options ?? this.#defaultAppOptions)
    )
    if (this.initApp) {
      this.initApp(app)
    }
    return app
  }

  createMiddleware = <I extends Input = {}, R extends HandlerResponse<any> | void = void>(
    middleware: MiddlewareHandler<E, P, I, R extends void ? Response : R>
  ): MiddlewareHandler<E, P, I, R extends void ? Response : R> => middleware

  createHandlers: CreateHandlersInterface<E, P> = (...handlers: any) => {
    // @ts-expect-error this should not be typed
    return handlers.filter((handler) => handler !== undefined)
  }
}

export const createFactory = <E extends Env = Env, P extends string = string>(init?: {
  initApp?: InitApp<E>
  defaultAppOptions?: HonoOptions<E>
}): Factory<E, P> => new Factory<E, P>(init)

export const createMiddleware = <
  E extends Env = any,
  P extends string = string,
  I extends Input = {},
  R extends HandlerResponse<any> | void = void,
>(
  middleware: MiddlewareHandler<E, P, I, R extends void ? Response : R>
): MiddlewareHandler<E, P, I, R extends void ? Response : R> => middleware

export const HonoXIsland = ({
  componentName,
  componentExport,
  Component,
  props,
}: {
  componentName: string
  componentExport: string
  Component: Function
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  props: any
}) => {
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const elementProps: Record<string, any> = {}
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const restProps: Record<string, any> = {}
  for (const key in props) {
    const value = props[key]
    if (isElementPropValue(value)) {
      elementProps[key] = value
    } else {
      restProps[key] = value
    }
  }

  const islandState = useContext(IslandContext)
  return islandState[inChildren] || !islandState[inIsland] ? (
    // top-level or slot content
    <honox-island
      {...{
        [COMPONENT_NAME]: componentName,
        [COMPONENT_EXPORT]: componentExport || undefined,
        [DATA_SERIALIZED_PROPS]: JSON.stringify(restProps),
      }}
    >
      <IslandContext.Provider value={{ ...islandState, [inIsland]: true }}>
        <Component {...props} />
      </IslandContext.Provider>
      {Object.entries(elementProps).map(([key, children]) => (
        <template {...{ [DATA_HONO_TEMPLATE]: key }} key={key}>
          <IslandContext.Provider value={{ ...islandState, [inChildren]: true }}>
            {children}
          </IslandContext.Provider>
        </template>
      ))}
    </honox-island>
  ) : (
    // nested component
    <Component {...props} />
  )
}

export const trpcServer = ({
  endpoint,
  createContext,
  ...rest
}: tRPCOptions): MiddlewareHandler => {
  const bodyProps = new Set(['arrayBuffer', 'blob', 'formData', 'json', 'text'] as const)
  type BodyProp = typeof bodyProps extends Set<infer T> ? T : never
  return async (c) => {
    const canWithBody = c.req.method === 'GET' || c.req.method === 'HEAD'

    // Auto-detect endpoint from route path if not explicitly provided
    let resolvedEndpoint = endpoint
    if (!endpoint) {
      const path = routePath(c)
      if (path) {
        // Remove wildcard suffix (e.g., "/v1/*" -> "/v1")
        resolvedEndpoint = path.replace(/\/\*+$/, '') || '/trpc'
      } else {
        resolvedEndpoint = '/trpc'
      }
    }

    const res = await fetchRequestHandler({
      ...rest,
      createContext: async (opts) => ({
        ...(createContext ? await createContext(opts, c) : {}),
        // propagate env by default
        env: c.env,
      }),
      endpoint: resolvedEndpoint!,
      req: canWithBody
        ? c.req.raw
        : new Proxy(c.req.raw, {
            get(t, p, _r) {
              if (bodyProps.has(p as BodyProp)) {
                return () => c.req[p as BodyProp]()
              }
              return Reflect.get(t, p, t)
            },
          }),
    })
    return res
  }
}

