import { raw } from '../helper/html'
import type { HtmlEscapedString } from '../utils/html'
import { JSXFragmentNode } from './base'
import { DOM_RENDERER } from './constants'
import { createContextProviderFunction } from './dom/context'
import type { FC, PropsWithChildren } from './'

export interface Context<T> extends FC<PropsWithChildren<{ value: T }>> {
  values: T[]
  Provider: FC<PropsWithChildren<{ value: T }>>
}

export const globalContexts: Context<unknown>[] = []

export const createContext = <T>(defaultValue: T): Context<T> => {
  const values = [defaultValue]
  const context: Context<T> = ((props): HtmlEscapedString | Promise<HtmlEscapedString> => {
    values.push(props.value)
    let string
    try {
      string = props.children
        ? (Array.isArray(props.children)
            ? new JSXFragmentNode('', {}, props.children)
            : props.children
          ).toString()
        : ''
    } catch (e) {
      values.pop()
      throw e
    }

    if (string instanceof Promise) {
      return string
        .finally(() => values.pop())
        .then((resString) => raw(resString, (resString as HtmlEscapedString).callbacks))
    } else {
      values.pop()
      return raw(string)
    }
  }) as Context<T>
  context.values = values
  context.Provider = context

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  ;(context as any)[DOM_RENDERER] = createContextProviderFunction(values)

  globalContexts.push(context as Context<unknown>)

  return context
}

export const useContext = <T>(context: Context<T>): T => {
  return context.values.at(-1) as T
}

import type { Context, MiddlewareHandler } from 'hono'
import { Toucan } from 'toucan-js'
import type { Options as ToucanOptions } from 'toucan-js'

declare module 'hono' {
  interface ContextVariableMap {
    sentry: Toucan
  }
}

class MockContext implements ExecutionContext {
  passThroughOnException(): void {
    throw new Error('Method not implemented.')
  }
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  async waitUntil(promise: Promise<any>): Promise<void> {
    await promise
  }
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  props: any
}

export type Options = Omit<ToucanOptions, 'request' | 'context'>

export const sentry = (
  options?: Options,
  callback?: (sentry: Toucan) => void
): MiddlewareHandler => {
  return async (c, next) => {
    let hasExecutionContext = true
    try {
      c.executionCtx
    } catch {
      hasExecutionContext = false
    }
    const sentry = new Toucan({
      dsn: c.env?.SENTRY_DSN ?? c.env?.NEXT_PUBLIC_SENTRY_DSN,
      requestDataOptions: {
        allowedHeaders: ['user-agent'],
        allowedSearchParams: /(.*)/,
      },
      request: c.req.raw,
      context: hasExecutionContext ? c.executionCtx : new MockContext(),
      ...options,
    })
    c.set('sentry', sentry)
    if (callback) {
      callback(sentry)
    }

    await next()
    if (c.error) {
      sentry.captureException(c.error)
    }
  }
}

export const getSentry = (c: Context): Toucan => {
  return c.get('sentry')
}

import type { Session } from '@/features/auth/models/session.type';
import type { User } from '@/features/user/models/user.type';
import type { Env } from '@/types';
import { getRandomBytes } from '@/utils/crypto';
import type { Context } from 'hono';

export const createSession = async (c: Context<Env>, user: User, expiresAt: Date): Promise<Session> => {
  const id = getRandomBytes(32);
  const data = {
    id,
    userId: user.id,
    createdAt: new Date(),
    updatedAt: new Date(),
    expiresAt: expiresAt,
  };
  await c.get('kv').put(`session_${id}`, JSON.stringify(data), {
    expiration: expiresAt.getTime() / 1000,
  });
  return data;
};

export const updateSessionExpiration = async (
  c: Context<Env>,
  sessionId: string,
  expiresAt: Date,
): Promise<Session> => {
  const session = await getSessionById(c, sessionId);
  if (session) {
    session.expiresAt = expiresAt;
    await c.get('kv').put(`session_${sessionId}`, JSON.stringify(session), {
      expiration: expiresAt.getTime() / 1000,
    });
  }
  return session;
};

export const getSessionById = async (c: Context<Env>, id: string) => {
  const data = await c.get('kv').get(`session_${id}`);
  return data ? JSON.parse(data) : null;
};

export const deleteSession = async (c: Context<Env>, sessionId: string) => {
  return c.get('kv').delete(`session_${sessionId}`);
};

import type { Child } from '../base'
import { DOM_ERROR_HANDLER } from '../constants'
import type { Context } from '../context'
import { globalContexts } from '../context'
import { setInternalTagFlag } from './utils'

export const createContextProviderFunction =
  <T>(values: T[]): Function =>
  ({ value, children }: { value: T; children: Child[] }) => {
    if (!children) {
      return undefined
    }

    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const props: { children: any } = {
      children: [
        {
          tag: setInternalTagFlag(() => {
            values.push(value)
          }),
          props: {},
        },
      ],
    }
    if (Array.isArray(children)) {
      props.children.push(...children.flat())
    } else {
      props.children.push(children)
    }
    props.children.push({
      tag: setInternalTagFlag(() => {
        values.pop()
      }),
      props: {},
    })
    const res = { tag: '', props, type: '' }
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    ;(res as any)[DOM_ERROR_HANDLER] = (err: unknown) => {
      values.pop()
      throw err
    }
    return res
  }

export const createContext = <T>(defaultValue: T): Context<T> => {
  const values = [defaultValue]
  const context: Context<T> = createContextProviderFunction(values) as Context<T>
  context.values = values
  context.Provider = context
  globalContexts.push(context as Context<unknown>)
  return context
}

import type { Context } from 'hono';
import { HTTPException } from 'hono/http-exception';
import type { ContentfulStatusCode } from 'hono/utils/http-status';
import { StatusCodes, getReasonPhrase } from 'http-status-codes';

const serveNotFound = (c: Context, message?: string) => {
  return c.json(
    { error: message || getReasonPhrase(StatusCodes.NOT_FOUND) },
    <ContentfulStatusCode>StatusCodes.NOT_FOUND,
  );
};
const serveBadRequest = (c: Context, message: string) => {
  return c.json({ error: message }, <ContentfulStatusCode>StatusCodes.BAD_REQUEST);
};

const serveUnprocessableEntity = (c: Context, message: string) => {
  return c.json({ error: message }, <ContentfulStatusCode>StatusCodes.UNPROCESSABLE_ENTITY);
};

const serveUnauthorized = (c: Context) => {
  return c.json({ error: getReasonPhrase(StatusCodes.UNAUTHORIZED) }, <ContentfulStatusCode>StatusCodes.UNAUTHORIZED);
};

const serveInternalServerError = (c: Context, error: any) => {
